const secret = $input.first().json.headers['x-ribuzz-secret'];
const expected = "Preseed2026+*";
if (!secret || secret !== expected) {
  throw new Error('Invalid webhook secret');
}
const body = $input.first().json.body;
if (!body?.job_id || !body?.diagnostic_id) {
  throw new Error('Missing job_id or diagnostic_id');
}
return [{ json: { job_id: body.job_id, diagnostic_id: body.diagnostic_id } }];

const answers = $input.all().map(i => i.json);
const flat = {};
for (const a of answers) {
  const vars = (a.variable_bd || '').split(',').map(v => v.trim());
  for (const v of vars) flat[v] = a.is_unknown ? '' : (a.answer_text || '');
}
function num(value, fallback = 0) {
  if (!value) return fallback;
  const normalized = value.toString().toLowerCase();
  const ranges = {
    menos_10: 5,
    '10_30': 20,
    '31_100': 65,
    mas_100: 120,
    '0': 0,
    '1_5': 3,
    '6_15': 10.5,
    '16_30': 23,
    mas_30: 40,
    no_se: fallback
  };
  if (Object.prototype.hasOwnProperty.call(ranges, normalized)) return ranges[normalized];
  const clean = normalized.replace(/[$,\s]/g, '');
  const m = clean.match(/\d+(?:\.\d+)?(?:k|m|mm)?/g);
  if (!m) return fallback;
  const nums = m.map(x => { let n = parseFloat(x); if (x.endsWith('mm') || x.endsWith('m')) n *= 1e6; else if (x.endsWith('k')) n *= 1e3; return n; });
  return nums.length >= 2 ? (nums[0] + nums[1]) / 2 : nums[0];
}
const ventas = num(flat.comercial_ventas_mes);
const clientes = Math.max(num(flat.comercial_clientes_actuales, 1), 1);
const nuevos = num(flat.comercial_clientes_nuevos || flat.ventas_30d);
const inversion = num(flat.comercial_inversion_mes);
const leads = Math.max(num(flat.comercial_leads_mes || flat.interesados_30d, 1), 1);
const ticketDeclarado = num(flat.ticket_promedio);
const conv = num(flat.comercial_tasa_conversion, leads > 0 ? (nuevos / leads) * 100 : 0);
const ticket_medio = ticketDeclarado > 0 ? ticketDeclarado : ventas / clientes;
const cac = nuevos > 0 ? inversion / nuevos : inversion;
const ltv = ticket_medio * 12;
const ratio_cac_ticket = ticket_medio > 0 ? (cac / ticket_medio) * 100 : 100;
const ratio_cac_ltv = ltv > 0 ? (cac / ltv) * 100 : 100;
const leads_perdidos = Math.round(leads * (1 - conv / 100));
const conv_obj = Math.min(conv / 100 + 0.1, 1);
const clientes_adicionales = Math.round(leads * (conv_obj - conv / 100));
const ingreso_potencial = clientes_adicionales * ticket_medio;
const s_ticket = Math.min(ticket_medio / 1e6, 1) * 100;
const s_cac = Math.max(0, 100 - ratio_cac_ticket);
const s_conv = Math.min(conv * 2, 100);
const s_ltv_cac = Math.max(0, 100 - ratio_cac_ltv);
const salud_comercial = Math.round(s_ticket * 0.25 + s_cac * 0.3 + s_conv * 0.25 + s_ltv_cac * 0.2);
const metrics = {
  ticket_medio: Math.round(ticket_medio),
  cac: Math.round(cac),
  ltv: Math.round(ltv),
  ratio_cac_ticket: Math.round(ratio_cac_ticket * 10) / 10,
  ratio_cac_ltv: Math.round(ratio_cac_ltv * 10) / 10,
  leads_perdidos,
  ingreso_potencial: Math.round(ingreso_potencial),
  salud_comercial
};
const company = $('Fetch Diagnostic + Company').first().json;
return [{ json: { answers, flat, metrics, company } }];

const raw = $input.first().json.text;
const p0 = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
const ctx = $('Code: Calculate Metrics').first().json;
return [{ json: { p0, company: ctx.company, answers: ctx.answers, flat: ctx.flat, metrics: ctx.metrics } }];

const raw = $input.first().json.text;
const p1 = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
const metricsCtx = $('Parse P0').first().json;
return [{ json: { p1, metrics: metricsCtx.metrics, company: metricsCtx.company, p0: metricsCtx.p0, p1_raw: raw } }];

// Restore context after Postgres UPDATE (Job → scoring returns {})
const ctx = $('Parse P1').first().json;
return [{ json: { p1: ctx.p1, metrics: ctx.metrics, company: ctx.company, p0: ctx.p0 } }];

const raw = $input.first().json.text || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON block found');
  parsed = JSON.parse(match[0]);
} catch(e) {
  return [{ json: { scores: {}, score_global: 0, parse_error: e.message } }];
}
const scores = parsed.scores || {};
const values = Object.values(scores).filter(v => typeof v?.score === 'number');
const score_global = values.length
  ? Math.round((values.reduce((s, v) => s + v.score, 0) / values.length) * 10) / 10
  : 0;
// Pass p0 through from Prep Scorer Input
const p0 = $('Prep Scorer Input').first().json.p0;
return [{ json: { scores, score_global, p0 } }];

const result = $input.first().json;
if (!result.scores || Object.keys(result.scores).length === 0) {
  throw new Error('Scorer sub-workflow returned empty scores. Check OpenAI response.');
}
return [{ json: result }];

const raw = $input.first().json.text;
const fugas = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
const ctx = $('Combine 14 Scores').first().json;
return [{ json: { ...ctx, top_fugas: fugas.top_fugas || [], p1: $('Prep Scorer Input').first().json.p1, metrics: $('Prep Scorer Input').first().json.metrics, company: $('Prep Scorer Input').first().json.company } }];

// Restore context after Postgres UPDATE (Job → reporting returns {})
const ctx = $('Parse Fugas').first().json;
return [{ json: ctx }];

const parse = (s) => { try { return JSON.parse(s.match(/\{[\s\S]*\}$/m)?.[0] || s); } catch(e) { return {}; } };
const ctx = $('Parse Fugas').first().json;
return [{ json: {
